	@Test
	public void testStrictComparisons() {
		cmp.setStrict(true);
		assertTrue(cmp.isStrict() == true);
		// In strict mode cross-type calendar values have no SPARQL-defined order, so the comparator retains the
		// existing CoreDatatype.XSD precedence: DATE is declared before GYEAR. STANDARD mode separately uses the
		// shared chronological calendar domain.
		Literal date1 = vf.createLiteral("2017-01-01", XSD.DATE);
		Literal date2 = vf.createLiteral("2018", XSD.GYEAR);
		assertTrue(cmp.compare(date1, date2) < 0);
		assertTrue(cmp.compare(date2, date1) > 0);
	}

	@Test
	public void testCalendarValueEqualsUseRdfTermTieBreak() {
		Literal utc = vf.createLiteral("2000-01-01T00:00:00Z", XSD.DATETIME);
		Literal sameLexicalForm = vf.createLiteral("2000-01-01T00:00:00Z", XSD.DATETIME);
		Literal sameInstantDifferentOffset = vf.createLiteral("1999-12-31T19:00:00-05:00", XSD.DATETIME);
		Literal sameInstantDifferentDatatype = vf.createLiteral("2000-01-01T00:00:00Z", XSD.DATETIMESTAMP);

		for (boolean strict : new boolean[] { true, false }) {
			cmp.setStrict(strict);
			assertEquals(0, cmp.compare(utc, sameLexicalForm),
					"equal RDF terms must remain comparator-equal (strict=" + strict + ")");
			int offsetOrder = Integer.signum(cmp.compare(utc, sameInstantDifferentOffset));
			assertNotEquals(0, offsetOrder,
					"different RDF terms denoting one instant need a deterministic tie-break (strict=" + strict + ")");
			assertEquals(-offsetOrder, Integer.signum(cmp.compare(sameInstantDifferentOffset, utc)));
		}

		cmp.setStrict(false);
		int datatypeOrder = Integer.signum(cmp.compare(utc, sameInstantDifferentDatatype));
		assertNotEquals(0, datatypeOrder,
				"STANDARD comparison must tie-break equal dateTime/dateTimeStamp values by RDF term");
		assertEquals(-datatypeOrder, Integer.signum(cmp.compare(sameInstantDifferentDatatype, utc)));
	}

	@Test
	public void testCalendarSortKeyRemainsLabelDerivedAfterBackingCalendarMutation() throws Exception {
		String label = "2000-01-01T00:00:00Z";
		XMLGregorianCalendar mutableCalendar = DatatypeFactory.newInstance().newXMLGregorianCalendar(label);
		Literal calendarBacked = new AbstractValueFactory() {
		}.createLiteral(mutableCalendar);
		Literal lexicalEquivalent = vf.createLiteral(label, XSD.DATETIME);
		Literal earlier = vf.createLiteral("1999-12-31T23:59:59Z", XSD.DATETIME);
		Literal later = vf.createLiteral("2000-01-01T00:00:01Z", XSD.DATETIME);

		ValueComparator warmedComparator = new ValueComparator();
		assertCalendarLabelOrder(warmedComparator, calendarBacked, lexicalEquivalent, earlier, later,
				"before mutation");

		mutableCalendar.setYear(2099);
		assertEquals(label, calendarBacked.getLabel(), "the RDF lexical form must remain immutable");

		assertCalendarLabelOrder(warmedComparator, calendarBacked, lexicalEquivalent, earlier, later,
				"after mutation with a warmed cache");

		FutureTask<Void> coldCacheCheck = new FutureTask<>(() -> {
			assertCalendarLabelOrder(new ValueComparator(), calendarBacked, lexicalEquivalent, earlier, later,
					"after mutation with a cold cache");
			return null;
		});
		Thread coldCacheThread = new Thread(coldCacheCheck, "calendar-sort-key-cold-cache");
		coldCacheThread.start();
		coldCacheCheck.get();
	}

	private static void assertCalendarLabelOrder(ValueComparator comparator, Literal calendarBacked,
			Literal lexicalEquivalent, Literal earlier, Literal later, String phase) {
		for (boolean strict : new boolean[] { true, false }) {
			comparator.setStrict(strict);
			String messageSuffix = " (strict=" + strict + ", " + phase + ")";
			assertEquals(0, comparator.compare(calendarBacked, lexicalEquivalent),
					"calendar ordering must come from the immutable RDF lexical form" + messageSuffix);
			assertTrue(comparator.compare(earlier, calendarBacked) < 0,
					"the earlier control must remain first" + messageSuffix);
			assertTrue(comparator.compare(calendarBacked, later) < 0,
					"the later control must remain last" + messageSuffix);
		}
	}
